#include<stdio.h>
#include<string.h>
char v[10001][12];int n=0;
int count(int i,int d,int k){
  if(i>=n||strcmp(v[i],"N")==0)return 0;
  if(d==k)return 1;
  return count(2*i+1,d+1,k)+count(2*i+2,d+1,k);
}
int main(){int k;scanf("%d",&k);while(scanf("%s",v[n])==1)n++;printf("%d\n",count(0,0,k));}
